// Java compilation and execution flow:

// 1. Write Java source
// HelloWorld.java
public class HelloWorld {
    public static void main(String[] args) {
        System.out.println("Hello, World!");
    }
}

// 2. Compile to bytecode (.class file)
// $ javac HelloWorld.java
// Creates: HelloWorld.class (platform-independent bytecode)

// 3. JVM executes bytecode
// $ java HelloWorld
// JVM Class Loader -> Bytecode Verifier -> Interpreter/JIT -> Native execution

// JVM internals structure:
// ┌──────────────────────────────────────┐
// │               JVM                    │
// │  ┌──────────┐  ┌────────────────┐   │
// │  │  Class   │  │  Runtime Data  │   │
// │  │  Loader  │  │  Areas (Heap,  │   │
// │  │  System  │  │  Stack, etc.)  │   │
// │  └──────────┘  └────────────────┘   │
// │  ┌──────────────────────────────┐   │
// │  │   Execution Engine           │   │
// │  │   (Interpreter + JIT + GC)   │   │
// │  └──────────────────────────────┘   │
// └──────────────────────────────────────┘

// JIT Compilation: hot methods compiled to native code at runtime
// First execution: interpreted (slow)
// After N executions: JIT compiles to optimized native machine code (fast)

// Understanding Java GC

// 1. Object lifecycle
public class GCDemo {
    public static void main(String[] args) {
        // Created in Eden (Young Gen)
        String msg = new String("hello");

        // After several Minor GCs, long-lived objects promoted to Old Gen
        List<String> cache = new ArrayList<>();
        for (int i = 0; i < 100_000; i++) {
            cache.add("item-" + i);  // kept alive by 'cache' reference
        }

        // When 'msg' goes out of scope, it becomes eligible for GC
        // JVM decides WHEN to collect (not immediate like Python)
    }

    // finalize() is deprecated (Java 9+) — don't use it
    // Use try-with-resources or Cleaner API instead
}

// 2. GC types and when to use each:
// Serial GC:   Single-threaded. Good for small heaps (<1GB). -XX:+UseSerialGC
// Parallel GC: Multi-threaded minor GC. Throughput-focused.  -XX:+UseParallelGC  
// G1 GC:       Balanced. Default since Java 9. Predictable pause times.
// ZGC:         Ultra-low latency (<1ms pause). Java 15+.      -XX:+UseZGC

// 3. Common GC flags
// -Xms512m -Xmx2g        (initial/max heap)
// -XX:+PrintGCDetails    (verbose GC logs)
// -XX:+HeapDumpOnOutOfMemoryError  (dump heap on OOM)

// 4. Memory leak example (unintentional reference retention)
public class LeakyCache {
    private static Map<String, Object> cache = new HashMap<>();

    public void add(String key, Object value) {
        cache.put(key, value);  // static map holds reference forever!
        // Fix: use WeakHashMap or an eviction policy
    }
}

