import java.util.*;

// ArrayList: fast indexed access, slow insert in middle
List<String> names = new ArrayList<>();
names.add("Alice");
names.get(0);           // O(1)
names.add(0, "Zara");   // O(N) - shifts elements

// LinkedList: fast add/remove at head/tail
Deque<String> queue = new LinkedList<>();
queue.addFirst("first");
queue.addLast("last");
queue.pollFirst();      // O(1)

// HashMap: O(1) average, no order guarantee
Map<String, Integer> scores = new HashMap<>();
scores.put("Alice", 95);
scores.getOrDefault("Bob", 0);  // 0
scores.computeIfAbsent("Charlie", k -> 50);

// TreeMap: sorted by key, O(log N)
Map<String, Integer> sorted = new TreeMap<>();
scores.forEach((k,v) -> sorted.put(k,v));
System.out.println(sorted.firstKey());  // alphabetically first

// LinkedHashMap: insertion order preserved
Map<String, Integer> ordered = new LinkedHashMap<>();

// HashSet: O(1) contains, no duplicates
Set<Integer> seen = new HashSet<>();
if (!seen.contains(5)) seen.add(5);

// PriorityQueue: min-heap by default
PriorityQueue<Integer> pq = new PriorityQueue<>();
pq.offer(5); pq.offer(1); pq.offer(3);
pq.poll();  // 1 (minimum)

// Max-heap using reverse comparator
PriorityQueue<Integer> maxHeap = new PriorityQueue<>(Comparator.reverseOrder());

// ArrayDeque: faster than LinkedList for stack/queue use
Deque<String> stack = new ArrayDeque<>();
stack.push("a"); stack.push("b");
stack.pop();  // "b" (LIFO)

import java.util.*;
import java.util.stream.*;

List<Employee> employees = List.of(
    new Employee("Alice", "Engineering", 90000),
    new Employee("Bob",   "Marketing",   60000),
    new Employee("Carol", "Engineering", 85000),
    new Employee("Dave",  "Marketing",   55000)
);

// Filter + Map + Collect
List<String> highEarners = employees.stream()
    .filter(e -> e.getSalary() > 70000)
    .map(Employee::getName)
    .sorted()
    .collect(Collectors.toList());  // ["Alice", "Carol"]

// Reduce: sum all salaries
long totalPayroll = employees.stream()
    .mapToLong(Employee::getSalary)
    .sum();

// GroupingBy: employees by department
Map<String, List<Employee>> byDept = employees.stream()
    .collect(Collectors.groupingBy(Employee::getDepartment));

// Average salary per department
Map<String, Double> avgSalaryByDept = employees.stream()
    .collect(Collectors.groupingBy(
        Employee::getDepartment,
        Collectors.averagingLong(Employee::getSalary)
    ));

// FlatMap: flatten nested structures
List<List<Integer>> nested = List.of(List.of(1,2), List.of(3,4));
List<Integer> flat = nested.stream()
    .flatMap(Collection::stream)
    .collect(Collectors.toList());  // [1, 2, 3, 4]

// Parallel stream: use with care, not always faster
long count = employees.parallelStream()
    .filter(e -> e.getSalary() > 70000)
    .count();

// Optional: stream-friendly null handling
Optional<Employee> topEarner = employees.stream()
    .max(Comparator.comparingLong(Employee::getSalary));
topEarner.ifPresent(e -> System.out.println(e.getName()));

// Interface: pure contract + default methods (Java 8+)
public interface Drawable {
    void draw();                          // abstract — must implement
    default void highlight() {            // default — can override
        System.out.println("Highlighting");
    }
    static Drawable circle(int r) {       // static factory
        return () -> System.out.println("Circle r=" + r);
    }
}

// Abstract class: partial implementation + state
public abstract class Shape {
    private final String color;  // state (interfaces can't have instance fields)

    public Shape(String color) {
        this.color = color;
    }

    public String getColor() { return color; }  // concrete method

    public abstract double area();  // subclasses must implement

    public void describe() {  // template method pattern
        System.out.printf("%s %s (area=%.2f)%n",
            color, getClass().getSimpleName(), area());
    }
}

// Circle extends abstract class AND implements multiple interfaces
public class Circle extends Shape implements Drawable, Comparable<Circle> {
    private final double radius;

    public Circle(String color, double radius) {
        super(color);  // must call abstract class constructor
        this.radius = radius;
    }

    @Override public double area() { return Math.PI * radius * radius; }
    @Override public void draw()   { System.out.println("Drawing circle"); }
    @Override public int compareTo(Circle other) {
        return Double.compare(this.radius, other.radius);
    }
}

