import java.util.Optional;

// Without Optional (null-unsafe)
public User findUser(String id) {
    return database.get(id);  // might return null!
}
// Caller: User u = findUser("123"); u.getName(); // NPE if null!

// With Optional (explicit absence)
public Optional<User> findUser(String id) {
    return Optional.ofNullable(database.get(id));
}

// Caller — forced to handle absence:
findUser("123")
    .map(User::getName)             // transform if present
    .map(String::toUpperCase)
    .orElse("Unknown");             // default if absent

// Chain with flatMap when inner method also returns Optional
findUser("123")
    .flatMap(user -> findAddress(user.getId()))  // Optional<Address>
    .map(Address::getCity)
    .orElse("City unknown");

// Conditional processing
findUser("123").ifPresent(user -> sendEmail(user));

// orElseThrow: explicit exception on absence
User user = findUser("123")
    .orElseThrow(() -> new UserNotFoundException("User 123 not found"));

// filter: narrow down
Optional<User> adminUser = findUser("123")
    .filter(u -> u.getRole().equals("ADMIN"));

// Bad practice: Optional.get() without isPresent() check
// NEVER do: findUser("123").get() -- throws NoSuchElementException if empty
// Use orElse, orElseGet, orElseThrow instead

public class MemoryDemo {
    // Static field: stored in Metaspace (class metadata)
    static final int MAX = 100;

    public void compute() {
        // Primitives: stored directly on the STACK
        int x = 5;          // 4 bytes on stack
        double y = 3.14;    // 8 bytes on stack
        boolean flag = true; // 1 bit (JVM uses 4 bytes) on stack

        // Object reference on STACK, object itself on HEAP
        String name = new String("Alice");  // reference on stack, String object on heap
        int[] arr = new int[10];            // reference on stack, array on heap

        // When compute() returns:
        // - x, y, flag are immediately gone (stack frame popped)
        // - name reference is gone, but String object stays on heap until GC
    }

    // Recursive method: each call adds a stack frame
    public int factorial(int n) {
        if (n <= 1) return 1;
        return n * factorial(n - 1);  // stack grows with each recursive call
        // factorial(10000) -> StackOverflowError!
    }

    // Memory-efficient: loop instead of recursion
    public int factorialLoop(int n) {
        int result = 1;
        for (int i = 2; i <= n; i++) result *= i;  // constant stack space
        return result;
    }
}

